class Counter {
  static count = 0;
  static increment() {
    this.count++;
  }
}
Counter.increment();

class Counter:
    shared_count = 0
    @classmethod
    def increment(cls):
        cls.shared_count += 1

public class Counter {
  public static int shared = 0;
  public static void increment() {
    shared++;
  }
}

CREATE TABLE shared_state (
  key TEXT PRIMARY KEY,
  value INTEGER
);
UPDATE shared_state SET value = value + 1 WHERE key = 'count';
